mapper.select:
SELECT class_id, class_name, people_limit, status FROM course_class
AND class_name LIKE CONCAT('%', #{search}, '%')
ORDER BY class_id LIMIT #{offset}, #{pageSize}

mapper.update:
UPDATE course
SET
    start_date = #{start_date},
    end_date = #{end_date}
WHERE course_id = #{course_id}

UPDATE course_class
SET class_name = #{class_name},
    people_limit = #{people_limit},
    status = #{status}
WHERE class_id = #{class_id}

UPDATE course_class
SET status = 0
WHERE class_name = #{class_name}
